import anthropic
import json

client = anthropic.Anthropic()

# Use tool use to enforce structured output — more reliable than examples
tools = [{
    "name": "classify_sentiment",
    "description": "Classify the sentiment of a customer review.",
    "input_schema": {
        "type": "object",
        "properties": {
            "label": {
                "type": "string",
                "enum": ["Positive", "Negative", "Neutral"],
                "description": "The sentiment label.",
            },
            "confidence": {
                "type": "number",
                "description": "Confidence score between 0 and 1.",
            },
            "reasoning": {
                "type": "string",
                "description": "One-sentence explanation of the classification.",
            },
        },
        "required": ["label", "confidence", "reasoning"],
    },
}]

def classify(text: str) -> dict:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=200,
        tools=tools,
        tool_choice={"type": "tool", "name": "classify_sentiment"},
        messages=[
            {"role": "user", "content": f"Classify this review: {text}"}
        ],
    )
    return resp.content[0].input

reviews = [
    "The screen is gorgeous but the battery life is terrible.",
    "Exactly as described, shipped in two days.",
    "It's fine, does the job.",
]

for review in reviews:
    result = classify(review)
    print(f"'{review[:45]}...'")
    print(f"  Label={result['label']}  Conf={result['confidence']:.2f}  {result['reasoning']}")
